import{_ as s,o as a,c as n,ag as o}from"./chunks/framework.DL0AyVxm.js";const u=JSON.parse('{"title":"Existing Projects","description":"","frontmatter":{},"headers":[],"relativePath":"guide/existing-projects.md","filePath":"guide/existing-projects.md"}'),t={name:"guide/existing-projects.md"};function i(r,e,l,d,p,c){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="existing-projects" tabindex="-1">Existing Projects <a class="header-anchor" href="#existing-projects" aria-label="Permalink to &quot;Existing Projects&quot;">​</a></h1><p>If your project already has some Claude Code configuration -- a <code>CLAUDE.md</code>, a <code>.claude/</code> directory, an <code>.mcp.json</code>, or any combination -- Worclaude detects it and uses a smart merge strategy instead of overwriting your work. This page explains exactly how that works.</p><h2 id="how-detection-works" tabindex="-1">How Detection Works <a class="header-anchor" href="#how-detection-works" aria-label="Permalink to &quot;How Detection Works&quot;">​</a></h2><p>When you run <code>worclaude init</code>, the detector checks three things:</p><ol><li>Does <code>.claude/workflow-meta.json</code> exist? If yes, this project was previously set up by Worclaude -- you will be redirected to use <code>worclaude upgrade</code> instead.</li><li>Does <code>.claude/</code>, <code>CLAUDE.md</code>, or <code>.mcp.json</code> exist (but no <code>workflow-meta.json</code>)? If yes, this is an existing project with manual Claude Code configuration -- <strong>Scenario B</strong>.</li><li>None of the above exist? This is a fresh project -- <strong>Scenario A</strong> (covered in <a href="/Worclaude/guide/getting-started.html">Getting Started</a>).</li></ol><p>This page covers Scenario B.</p><h2 id="what-gets-detected" tabindex="-1">What Gets Detected <a class="header-anchor" href="#what-gets-detected" aria-label="Permalink to &quot;What Gets Detected&quot;">​</a></h2><p>When Worclaude detects an existing setup, it scans your project and shows a report:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Worclaude v1.1.0</span></span>
<span class="line"><span>  ─────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Detected existing Claude Code setup:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  CLAUDE.md ................. exists (38 lines)</span></span>
<span class="line"><span>  .claude/settings.json ..... exists</span></span>
<span class="line"><span>  .claude/skills/ ........... 9 files found</span></span>
<span class="line"><span>  .claude/agents/ ........... not found</span></span>
<span class="line"><span>  .claude/commands/ ......... not found</span></span>
<span class="line"><span>  .mcp.json ................. exists</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  A backup will be created before any changes.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? Proceed? (Y/n)</span></span></code></pre></div><p>The detector examines:</p><ul><li><strong>CLAUDE.md</strong> -- Whether it exists and how many lines it contains</li><li><strong>.claude/settings.json</strong> -- Whether permissions and hooks are already configured</li><li><strong>.claude/skills/</strong> -- Which skill files you have</li><li><strong>.claude/agents/</strong> -- Which agent files you have</li><li><strong>.claude/commands/</strong> -- Which command files you have</li><li><strong>.mcp.json</strong> -- Whether MCP server configuration exists</li><li><strong>docs/spec/PROGRESS.md</strong> and <strong>docs/spec/SPEC.md</strong> -- Whether spec documents exist</li></ul><h2 id="automatic-backup" tabindex="-1">Automatic Backup <a class="header-anchor" href="#automatic-backup" aria-label="Permalink to &quot;Automatic Backup&quot;">​</a></h2><p>Before making any changes, Worclaude creates a timestamped backup of your entire Claude Code setup:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Creating backup...</span></span>
<span class="line"><span>  ✓ Backed up to .claude-backup-20260323-143022/</span></span></code></pre></div><p>The backup contains copies of <code>CLAUDE.md</code>, the entire <code>.claude/</code> directory, and <code>.mcp.json</code>. If anything goes wrong, you can restore from this backup using <code>worclaude restore</code>.</p><p>After the backup, Worclaude runs the same interactive prompts as a fresh install (project name, description, project type, tech stack, agent selection). Your answers determine what the workflow wants to install.</p><h2 id="the-three-merge-tiers" tabindex="-1">The Three Merge Tiers <a class="header-anchor" href="#the-three-merge-tiers" aria-label="Permalink to &quot;The Three Merge Tiers&quot;">​</a></h2><p>Worclaude uses a tiered merge strategy designed to never destroy your work. Each file falls into one of three tiers based on whether a conflict exists.</p><h3 id="tier-1-additive-automatic-no-prompt" tabindex="-1">Tier 1: Additive (Automatic, No Prompt) <a class="header-anchor" href="#tier-1-additive-automatic-no-prompt" aria-label="Permalink to &quot;Tier 1: Additive (Automatic, No Prompt)&quot;">​</a></h3><p>Files that do not conflict with anything you already have are added silently:</p><ul><li><strong>Missing skills</strong> are added directly to <code>.claude/skills/</code></li><li><strong>Missing agents</strong> are added to <code>.claude/agents/</code> (both universal and your selected optional agents)</li><li><strong>Missing commands</strong> are added to <code>.claude/commands/</code></li><li><strong>settings.json permissions</strong> -- new permission rules are appended to your existing allow list without removing any of your existing rules</li><li><strong>settings.json hooks</strong> -- new hooks are appended if their matcher does not conflict with an existing hook</li><li><strong>.mcp.json</strong> -- missing MCP servers are added; your existing servers take priority if there is a name collision</li><li><strong>docs/spec/PROGRESS.md</strong> -- created if missing, skipped if it already exists</li><li><strong>docs/spec/SPEC.md</strong> -- created if missing, skipped if it already exists</li><li><strong>.claude/workflow-meta.json</strong> -- always created (this is how Worclaude tracks that it has been installed)</li></ul><h3 id="tier-2-safe-alongside-notify-do-not-ask" tabindex="-1">Tier 2: Safe Alongside (Notify, Do Not Ask) <a class="header-anchor" href="#tier-2-safe-alongside-notify-do-not-ask" aria-label="Permalink to &quot;Tier 2: Safe Alongside (Notify, Do Not Ask)&quot;">​</a></h3><p>When Worclaude wants to install a file that you already have (for example, a skill or agent with the same name), it does not overwrite yours. Instead, it saves the workflow version alongside your file with a <code>.workflow-ref.md</code> suffix:</p><ul><li>Your <code>context-management.md</code> stays untouched</li><li>The workflow version is saved as <code>context-management.workflow-ref.md</code></li></ul><p>This applies to conflicting skills, agents, and commands. You get a notification in the final report but are never prompted to choose during the merge.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Conflicts (saved alongside for review):</span></span>
<span class="line"><span>  ~ context-management.md → context-management.workflow-ref.md</span></span>
<span class="line"><span>  ~ git-conventions.md → git-conventions.workflow-ref.md</span></span>
<span class="line"><span>  ~ testing.md → testing.workflow-ref.md</span></span></code></pre></div><h3 id="tier-3-interactive-asks-you" tabindex="-1">Tier 3: Interactive (Asks You) <a class="header-anchor" href="#tier-3-interactive-asks-you" aria-label="Permalink to &quot;Tier 3: Interactive (Asks You)&quot;">​</a></h3><p>Two types of conflicts require your input:</p><p><strong>Hook conflicts</strong> -- When an existing hook has the same matcher as a workflow hook but a different command, Worclaude asks what to do:</p><ul><li><strong>Replace</strong> -- Use the workflow hook</li><li><strong>Chain</strong> -- Combine both hooks with <code>&amp;&amp;</code></li><li><strong>Keep</strong> -- Keep your existing hook</li></ul><p><strong>CLAUDE.md</strong> -- This gets special handling (see below).</p><h2 id="claude-md-special-handling" tabindex="-1">CLAUDE.md Special Handling <a class="header-anchor" href="#claude-md-special-handling" aria-label="Permalink to &quot;CLAUDE.md Special Handling&quot;">​</a></h2><p>Your <code>CLAUDE.md</code> is the most important file in your Claude Code setup. Worclaude treats it with extra care.</p><p>First, Worclaude checks which recommended sections your <code>CLAUDE.md</code> is missing. The recommended sections are: Session Protocol, Critical Rules, Skills pointer, and Gotchas.</p><p>If your <code>CLAUDE.md</code> already has all recommended sections, Worclaude tells you and moves on without any changes.</p><p>If sections are missing, you are given three options:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Your CLAUDE.md (38 lines) was detected.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  The workflow recommends these additions:</span></span>
<span class="line"><span>  [+] Session Protocol section (Start/During/End)</span></span>
<span class="line"><span>  [+] Critical Rules: self-healing, subagent usage</span></span>
<span class="line"><span>  [+] Skills pointer section (progressive disclosure)</span></span>
<span class="line"><span>  [+] Gotchas section (empty, grows during development)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>? How would you like to handle CLAUDE.md?</span></span>
<span class="line"><span>  ◉ Keep mine, save suggestions to CLAUDE.md.workflow-suggestions</span></span>
<span class="line"><span>  ○ Show me a side-by-side comparison</span></span>
<span class="line"><span>  ○ Merge interactively section by section</span></span></code></pre></div><p><strong>Option 1 (default): Keep yours, save suggestions</strong> -- Your <code>CLAUDE.md</code> is untouched. A <code>CLAUDE.md.workflow-suggestions</code> file is created next to it with the recommended additions. You can review and manually integrate what you want.</p><p><strong>Option 2: Side-by-side comparison</strong> -- See your version and the workflow version side by side to understand the differences.</p><p><strong>Option 3: Interactive section merge</strong> -- Go through each missing section and decide whether to append it to your <code>CLAUDE.md</code>.</p><h2 id="after-the-merge" tabindex="-1">After the Merge <a class="header-anchor" href="#after-the-merge" aria-label="Permalink to &quot;After the Merge&quot;">​</a></h2><p>When the merge completes, you see a full report:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Merge complete!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Added automatically:</span></span>
<span class="line"><span>  ✓ 9 agents added</span></span>
<span class="line"><span>  ✓ 10 commands added</span></span>
<span class="line"><span>  ✓ 6 skills added (3 conflicts saved as .workflow-ref.md)</span></span>
<span class="line"><span>  ✓ 18 permission rules appended to settings.json</span></span>
<span class="line"><span>  ✓ 3 hooks added to settings.json</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Conflicts (saved alongside for review):</span></span>
<span class="line"><span>  ~ context-management.md → context-management.workflow-ref.md</span></span>
<span class="line"><span>  ~ git-conventions.md → git-conventions.workflow-ref.md</span></span>
<span class="line"><span>  ~ testing.md → testing.workflow-ref.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Suggestions:</span></span>
<span class="line"><span>  ~ CLAUDE.md.workflow-suggestions (review and merge manually)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Backup: .claude-backup-20260323-143022/</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  What to do next:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  1. Review .workflow-ref.md files and merge what&#39;s useful</span></span>
<span class="line"><span>  2. Review CLAUDE.md.workflow-suggestions</span></span>
<span class="line"><span>  3. Delete .workflow-ref.md and .workflow-suggestions files when done</span></span>
<span class="line"><span>  Run /setup in Claude Code for project-specific configuration</span></span></code></pre></div><h3 id="reviewing-workflow-ref-md-files" tabindex="-1">Reviewing <code>.workflow-ref.md</code> Files <a class="header-anchor" href="#reviewing-workflow-ref-md-files" aria-label="Permalink to &quot;Reviewing \`.workflow-ref.md\` Files&quot;">​</a></h3><p>These files contain the workflow&#39;s version of files you already had. Open them side by side with your versions and merge anything useful. For example, the workflow&#39;s <code>testing.md</code> might have testing patterns you have not considered.</p><p>Once you have merged what you want, delete the <code>.workflow-ref.md</code> files -- they are reference copies, not active configuration.</p><h3 id="reviewing-claude-md-workflow-suggestions" tabindex="-1">Reviewing <code>CLAUDE.md.workflow-suggestions</code> <a class="header-anchor" href="#reviewing-claude-md-workflow-suggestions" aria-label="Permalink to &quot;Reviewing \`CLAUDE.md.workflow-suggestions\`&quot;">​</a></h3><p>If you chose to keep your <code>CLAUDE.md</code>, the suggestions file contains the sections Worclaude recommends adding. Review each section and copy what fits your workflow into your actual <code>CLAUDE.md</code>.</p><p>Delete the file when you are done.</p><h3 id="running-setup" tabindex="-1">Running <code>/setup</code> <a class="header-anchor" href="#running-setup" aria-label="Permalink to &quot;Running \`/setup\`&quot;">​</a></h3><p>After the merge, start Claude Code and run <code>/setup</code>. This conversational interview fills in the template skills and other placeholder content with your project&#39;s real details. It works the same way whether you did a fresh install or a merge.</p><h2 id="restoring-from-backup" tabindex="-1">Restoring from Backup <a class="header-anchor" href="#restoring-from-backup" aria-label="Permalink to &quot;Restoring from Backup&quot;">​</a></h2><p>If something went wrong or you want to undo the merge entirely:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">worclaude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span></span></code></pre></div><p>This shows your available backups and lets you restore one. The restore replaces your current Claude Code setup with the backup contents.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/Worclaude/guide/upgrading.html">Upgrading</a> -- How to update when new Worclaude versions are released</li><li><a href="/Worclaude/guide/workflow-tips.html">Workflow Tips</a> -- Best practices for using the workflow after setup</li><li><a href="/Worclaude/guide/getting-started.html">Getting Started</a> -- For fresh projects without existing configuration</li></ul>`,57)])])}const g=s(t,[["render",i]]);export{u as __pageData,g as default};
